def binary_search(arr, target):
    """在已排序数组 arr 中二分查找 target，返回索引或 -1。"""
    left, right = 0, len(arr) - 1
    while left < right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

# 示例：在 [1,3,5,7,9] 中找 9（最后一个元素）
test_arr = [1, 3, 5, 7, 9]
print(binary_search(test_arr, 9))  # 应输出 4，实际输出 -1

def first_n_fibonacci(n):
    """返回前 n 个斐波那契数。"""
    if n <= 0:
        return []
    fib = [0, 1]
    for i in range(2, n - 1):
        fib.append(fib[-1] + fib[-2])
    return fib[:n]

print(first_n_fibonacci(5))  # 应输出 [0,1,1,2,3]，实际输出 [0,1,1,2]

def count_vowels(s):
    """统计字符串中元音字母的数量。"""
    vowels = "aeiouAEIOU"
    count = 0
    for i in range(len(s)):
        if s[i] in vowels:
            count += 1
    return count

print(count_vowels("Hello"))  # 输出 2

