import threading, time

class LazyInit:
    def __init__(self):
        self._data = None
        self._init_count = 0

    def get_data(self):
        if self._data is None:
            self._init_count += 1
            time.sleep(0.001)
            self._data = self._expensive_init()
        return self._data

    def _expensive_init(self):
        return {"loaded": True, "init_count": self._init_count}

obj = LazyInit()
threads = [threading.Thread(target=obj.get_data) for _ in range(10)]
for t in threads: t.start()
for t in threads: t.join()
print(obj.get_data())  # init_count 可能 >1

import threading

